SELECT * FROM ( SELECT ROWNUM AS rnum, A.* FROM ( SELECT R.reservation_id, R.user_id, R.place_id, TRUNC(R.check_in) AS check_in, TRUNC(R.check_out) AS check_out, R.visit_time, R.guest_count, R.request_note, R.status, R.payment_id, R.created_at, P.name, P.address, P.place_type FROM RESERVATION R LEFT JOIN PLACE P ON R.place_id = P.place_id
(R.user_id LIKE '%'||#{keyword}||'%' OR R.reservation_id LIKE '%'||#{keyword}||'%')
AND R.status IN
#{item}
AND P.place_type IN
#{item}
ORDER BY
R.check_in ASC R.check_in DESC R.status ASC R.created_at DESC
) A ) WHERE rnum BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*) FROM RESERVATION R LEFT JOIN PLACE P ON R.place_id = P.place_id
(R.user_id LIKE '%'||#{keyword}||'%' OR R.reservation_id LIKE '%'||#{keyword}||'%')
AND R.status IN
#{item}
AND P.place_type IN
#{item}
